SELECT * FROM learning_resources WHERE status = 'PUBLISHED'
AND file_type = #{fileType}
AND ( title LIKE CONCAT('%', #{query}, '%') OR description LIKE CONCAT('%', #{query}, '%') OR file_url LIKE CONCAT('%', #{query}, '%') )
ORDER BY
created_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM learning_resources WHERE status = 'PUBLISHED'
AND file_type = #{fileType}
AND (title LIKE CONCAT('%', #{query}, '%') OR description LIKE CONCAT('%', #{query}, '%') OR file_url LIKE CONCAT('%', #{query}, '%'))

SELECT * FROM learning_resources WHERE status = 'PUBLISHED' AND ( (#{query} IS NULL OR #{query} = '') OR (title LIKE CONCAT('%', #{query}, '%') OR description LIKE CONCAT('%', #{query}, '%')) ) ORDER BY
(CASE WHEN #{query} IS NULL OR #{query} = '' THEN 1 WHEN title LIKE CONCAT('%', #{query}, '%') THEN 3 WHEN description LIKE CONCAT('%', #{query}, '%') THEN 2 ELSE 1 END) DESC, created_time DESC
LIMIT #{offset}, #{limit}

SELECT * FROM learning_resources
WHERE (file_type = #{fileType} OR #{fileType} IS NULL OR #{fileType} = '')
AND status = #{status}
ORDER BY created_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM learning_resources 
WHERE status = #{status}

    AND file_type = #{fileType}
